  1→import { type PropsWithChildren, createContext, useCallback, useContext, useEffect, useMemo, useState } from 'react';
  2→import type { AuthChangeEvent, Session, User } from '@supabase/supabase-js';
  3→import { useLocation, useNavigate } from 'react-router-dom';
  4→import { isSupabaseConfigured, supabase } from '../lib/supabase';
  5→import { DEMO_USER_ID, demoProfile } from '../lib/demo-data';
  6→import type { Profile } from '../lib/types';
  7→import { hasProfileSectorTargets } from '../utils/sector-targeting';
  8→
  9→interface AuthContextValue {
 10→  user: User | null;
 11→  profile: Profile | null;
 12→  loading: boolean;
 13→  error: string | null;
 14→  login: (email: string, password: string) => Promise<boolean>;
 15→  signup: (email: string, password: string, fullName: string) => Promise<boolean>;
 16→  logout: () => Promise<void>;
 17→  resetPassword: (email: string) => Promise<boolean>;
 18→  clearError: () => void;
 19→  refreshProfile: () => Promise<void>;
 20→  patchProfile: (patch: Partial<Profile>) => Promise<boolean>;
 21→}
 22→
 23→const AuthContext = createContext<AuthContextValue | undefined>(undefined);
 24→const DEMO_AUTH_STORAGE_KEY = 'leadradar_demo_auth';
 25→const DEMO_PROFILE_STORAGE_KEY = 'leadradar_demo_profile';
 26→
 27→const createDemoUser = (email: string, fullName: string): User =>
 28→  ({
 29→    id: DEMO_USER_ID,
 30→    email,
 31→    aud: 'authenticated',
 32→    app_metadata: {},
 33→    user_metadata: { full_name: fullName },
 34→    created_at: new Date().toISOString(),
 35→  }) as User;
 36→
 37→const readDemoSession = (): { email: string; fullName: string } => {
 38→  if (typeof window === 'undefined') {
 39→    return { email: demoProfile.email, fullName: demoProfile.full_name ?? 'Compte Demo' };
 40→  }
 41→  const raw = window.localStorage.getItem(DEMO_AUTH_STORAGE_KEY);
 42→  if (!raw) {
 43→    return { email: demoProfile.email, fullName: demoProfile.full_name ?? 'Compte Demo' };
 44→  }
 45→  try {
 46→    const parsed = JSON.parse(raw) as { email?: string; fullName?: string };
 47→    return {
 48→      email: parsed.email ?? demoProfile.email,
 49→      fullName: parsed.fullName ?? demoProfile.full_name ?? 'Compte Demo',
 50→    };
 51→  } catch {
 52→    return { email: demoProfile.email, fullName: demoProfile.full_name ?? 'Compte Demo' };
 53→  }
 54→};
 55→
 56→const writeDemoSession = (email: string, fullName: string): void => {
 57→  if (typeof window === 'undefined') {
 58→    return;
 59→  }
 60→  window.localStorage.setItem(
 61→    DEMO_AUTH_STORAGE_KEY,
 62→    JSON.stringify({
 63→      email,
 64→      fullName,
 65→    }),
 66→  );
 67→};
 68→
 69→const normalizeProfile = (profile: Profile): Profile => {
 70→  const targetSectorIds =
 71→    Array.isArray(profile.target_sector_ids) && profile.target_sector_ids.length > 0
 72→      ? profile.target_sector_ids.filter((sectorId): sectorId is string => typeof sectorId === 'string' && Boolean(sectorId.trim()))
 73→      : profile.sector_id
 74→        ? [profile.sector_id]
 75→        : [];
 76→
 77→  return {
 78→    ...profile,
 79→    target_sector_ids: targetSectorIds,
 80→    target_sectors_json: Array.isArray(profile.target_sectors_json) ? profile.target_sectors_json : [],
 81→    sources_config: profile.sources_config ?? {},
 82→  };
 83→};
 84→
 85→const buildDemoProfile = (email: string, fullName: string, patch?: Partial<Profile>): Profile =>
 86→  normalizeProfile({
 87→    ...demoProfile,
 88→    ...patch,
 89→    email,
 90→    full_name: fullName,
 91→    updated_at: new Date().toISOString(),
 92→  });
 93→
 94→const readDemoProfile = (email: string, fullName: string): Profile => {
 95→  if (typeof window === 'undefined') {
 96→    return buildDemoProfile(email, fullName);
 97→  }
 98→  const raw = window.localStorage.getItem(DEMO_PROFILE_STORAGE_KEY);
 99→  if (!raw) {
100→    return buildDemoProfile(email, fullName);
101→  }
102→  try {
103→    const parsed = JSON.parse(raw) as Partial<Profile>;
104→    return buildDemoProfile(email, fullName, parsed);
105→  } catch {
106→    return buildDemoProfile(email, fullName);
107→  }
108→};
109→
110→const writeDemoProfile = (profile: Profile): void => {
111→  if (typeof window === 'undefined') {
112→    return;
113→  }
114→  window.localStorage.setItem(DEMO_PROFILE_STORAGE_KEY, JSON.stringify(profile));
115→};
116→
117→/**
118→ * Charge le profil applicatif depuis Supabase.
119→ */
120→const readProfile = async (user: User): Promise<Profile | null> => {
121→  const { data, error } = await supabase.from('profiles').select('*').eq('id', user.id).maybeSingle<Profile>();
122→  if (error) {
123→    throw error;
124→  }
125→  return data ? normalizeProfile(data) : null;
126→};
